document.addEventListener("DOMContentLoaded", function () {
  "use strict";

  // 1. Back to Top button visibility
  const backToTop = document.querySelector(".backtotop");
  window.addEventListener("scroll", function () {
    if (backToTop) {
      backToTop.style.display = window.scrollY > 200 ? "block" : "none";
    }
  });

  // 2. Smooth scroll to top when clicking the scroll button
  document.querySelectorAll(".scroll").forEach(function (btn) {
    btn.addEventListener("click", function (e) {
      e.preventDefault();
      window.scrollTo({ top: 0, behavior: "smooth" });
    });
  });

  // 3. Sticky header effect on scroll
  const header = document.querySelector(".site_header");
  window.addEventListener("scroll", function () {
    if (header) {
      header.classList.toggle("sticky", window.scrollY > 0);
    }
  });

  // 4. Toggle active state for pricing items
  const pricingBtn = document.querySelector(".pricing_toggle_btn");
  if (pricingBtn) {
    pricingBtn.addEventListener("click", function () {
      this.classList.toggle("active");
      document.querySelectorAll(".pricing_item").forEach(function (item) {
        item.classList.toggle("active");
      });
    });
  }

  // 5. Navigation Logic (Scroll Spy & Cross-page Smooth Scroll)
  const navLinks = document.querySelectorAll(
    ".main_menu_list .nav-link, .info_list a",
  );
  const sections = document.querySelectorAll("section[id], div[id]");

  // Handle incoming hash from another page (e.g., from subpage to index.html#about)
  if (window.location.hash) {
    const target = document.querySelector(window.location.hash);
    if (target) {
      setTimeout(() => {
        window.scrollTo({ top: target.offsetTop - 80, behavior: "smooth" });
        history.replaceState(null, null, window.location.pathname); // Clean URL
      }, 300);
    }
  }

  // Scroll Spy: Update active class on scroll
  window.addEventListener("scroll", () => {
    let current = "";
    sections.forEach((section) => {
      if (window.scrollY >= section.offsetTop - 150)
        current = section.getAttribute("id");
    });

    navLinks.forEach((link) => {
      link.parentElement.classList.remove("active");
      if (link.getAttribute("href").includes("#" + current))
        link.parentElement.classList.add("active");
    });
  });

  // Click Event: Internal smooth scroll & URL cleaning
  navLinks.forEach((link) => {
    link.addEventListener("click", function (e) {
      const href = this.getAttribute("href");
      if (href.includes("#")) {
        const targetId = href.substring(href.indexOf("#"));
        const targetElement = document.querySelector(targetId);

        // If target exists on current page
        if (targetElement) {
          e.preventDefault();
          window.scrollTo({
            top: targetElement.offsetTop - 80,
            behavior: "smooth",
          });

          // Sync active class across all menus
          navLinks.forEach((item) =>
            item.parentElement.classList.remove("active"),
          );
          navLinks.forEach((item) => {
            if (item.getAttribute("href") === href)
              item.parentElement.classList.add("active");
          });
        }
      }
    });
  });
});
